import { d3_area, d3_curves } from '../../../core/d3-constants'
import { getMarkValue } from '../../parser/parser-helpers'
function areaMark(config, cache){
    return {
        config: {
            d: function(d, i){
                let node = this,
                    _args = [d, i],
                    newConfig = config.d ? getMarkValue(node, _args, config, 'd', cache) : config,
                    interpolation = getMarkValue(node, _args, newConfig, 'curve', cache);
                let layout = d3_area()
                                .defined((d,i) => {
                                    let args = [d, i];
                                    return getMarkValue(node, args, newConfig, 'defined', cache);
                                })
                                .curve(d3_curves(interpolation));

                if(config.x){
                    layout = layout.x((d,i)=>{
                        let args = [d, i];
                        return getMarkValue(node, args, newConfig, 'x', cache);
                    })
                }
                if(config.x0){
                    layout = layout.x0((d,i)=>{
                        let args = [d, i];
                        return getMarkValue(node, args, newConfig, 'x0', cache);
                    })
                }
                if(config.x1){
                    layout = layout.x1((d,i)=>{
                        let args = [d, i];
                        return getMarkValue(node, args, newConfig, 'x1', cache);
                    })
                }

                if(config.y){
                    layout = layout.y((d,i)=>{
                        let args = [d, i];
                        return getMarkValue(node, args, newConfig, 'y', cache);
                    })
                }
                if(config.y0){
                    layout = layout.y0((d,i)=>{
                        let args = [d, i];
                        return getMarkValue(node, args, newConfig, 'y0', cache);
                    })
                }
                if(config.y1){
                    layout = layout.y1((d,i)=>{
                        let args = [d, i];
                        return getMarkValue(node, args, newConfig, 'y1', cache);
                    })
                }
                return layout(d);
            }
        },
        depends: {
            d: ['x','y','curve']
        }
    }

}

export { areaMark }